// Normalize and validate incoming quote request data
const body = $input.first().json.body || $input.first().json;

const origin = (body.origin || body['ต้นทาง'] || '').toString().trim().toUpperCase();
const destination = (body.destination || body['ปลายทาง'] || '').toString().trim().toUpperCase();
const weightKg = parseFloat(body.weight_kg || body['น้ำหนัก'] || 0);
const lengthCm = parseFloat(body.length_cm || body['ความยาว'] || 0);
const widthCm = parseFloat(body.width_cm || body['ความกว้าง'] || 0);
const heightCm = parseFloat(body.height_cm || body['ความสูง'] || 0);
const shipmentType = (body.shipment_type || body['ประเภทการขนส่ง'] || 'Air').toString().trim();
const customerName = (body.customer_name || body['ชื่อลูกค้า'] || '').toString().trim();
const contact = (body.contact || body['ติดต่อ'] || '').toString().trim();
const commodity = (body.commodity || body['ประเภทสินค้า'] || '').toString().trim();
const notes = (body.notes || body['หมายเหตุ'] || '').toString().trim();

// Calculate CBM
const cbm = parseFloat(((lengthCm * widthCm * heightCm) / 1000000).toFixed(4));

// Calculate Chargeable Weight
let chargeableWeight = weightKg;
if (shipmentType.toLowerCase().includes('air')) {
  chargeableWeight = Math.max(weightKg, cbm * 167);
} else if (shipmentType.toLowerCase().includes('lcl')) {
  chargeableWeight = Math.max(weightKg / 1000, cbm);
}
chargeableWeight = parseFloat(chargeableWeight.toFixed(2));

// Generate Quote ID
const now = new Date();
const dateStr = now.toISOString().slice(0,10).replace(/-/g,'');
const randomSuffix = Math.floor(1000 + Math.random() * 9000);
const quoteId = `QT-${dateStr}-${randomSuffix}`;

// Route key for Rate Table lookup
const routeKey = `${origin}-${destination}`;

return [{
  json: {
    quoteId,
    dateReceived: now.toISOString(),
    customerName,
    contact,
    origin,
    destination,
    routeKey,
    shipmentType,
    commodity,
    weightKg,
    lengthCm,
    widthCm,
    heightCm,
    cbm,
    chargeableWeight,
    notes
  }
}];

// Look up rate for the route and calculate total price
const quoteData = $('Normalize & Calculate CBM').first().json;
const rateRows = $('Get Rate Table').all().map(r => r.json);

// Read USD/THB exchange rate from environment variable (REQUIRED — do not hardcode)
const usdThb = parseFloat($env.USD_THB || '0');
if (usdThb <= 0) {
  return [{
    json: {
      ...quoteData,
      error: 'USD_THB rate not configured. Set USD_THB environment variable.',
      requiresManualQuote: true,
      freightCharge: 0,
      docFee: 0,
      otherCharges: 0,
      totalPrice: 0,
      quoteStatus: 'DRAFT — Pending Internal Approval'
    }
  }];
}

// Read quote validity days from environment variable
const validityDays = parseInt($env.QUOTE_VALIDITY_DAYS || '30');

const route = quoteData.routeKey;
const shipmentType = quoteData.shipmentType.toLowerCase();

// Find matching rate row
const rateRow = rateRows.find(r => {
  const rowRoute = (r['Route'] || '').toString().trim().toUpperCase();
  return rowRoute === route;
});

if (!rateRow) {
  return [{
    json: {
      ...quoteData,
      error: `No rate found for route: ${route}`,
      requiresManualQuote: true,
      freightCharge: 0,
      docFee: 0,
      otherCharges: 0,
      totalPrice: 0,
      quoteStatus: 'DRAFT — Pending Internal Approval'
    }
  }];
}

// Land shipments: no verified rate in table — always require manual quote
if (shipmentType.includes('land')) {
  return [{
    json: {
      ...quoteData,
      error: 'Land shipment: no verified rate available. Requires manual quote.',
      requiresManualQuote: true,
      freightCharge: 0,
      docFee: 0,
      otherCharges: 0,
      totalPrice: 0,
      quoteStatus: 'DRAFT — Pending Internal Approval'
    }
  }];
}

// Calculate freight charge based on shipment type
let freightCharge = 0;
const chargeableWeight = quoteData.chargeableWeight;
const cbm = quoteData.cbm;

if (shipmentType.includes('air')) {
  const airRate = parseFloat(rateRow['Air Rate (THB/kg)'] || 0);
  freightCharge = chargeableWeight * airRate;
} else if (shipmentType.includes('fcl') && shipmentType.includes('20')) {
  freightCharge = parseFloat(rateRow['Sea FCL 20ft (USD)'] || 0) * usdThb;
} else if (shipmentType.includes('fcl') && shipmentType.includes('40')) {
  freightCharge = parseFloat(rateRow['Sea FCL 40ft (USD)'] || 0) * usdThb;
} else if (shipmentType.includes('lcl')) {
  const lclRate = parseFloat(rateRow['Sea LCL (USD/CBM)'] || 0);
  freightCharge = Math.max(cbm, chargeableWeight) * lclRate * usdThb;
} else {
  return [{
    json: {
      ...quoteData,
      error: `Unknown shipment type: ${quoteData.shipmentType}. Requires manual quote.`,
      requiresManualQuote: true,
      freightCharge: 0,
      docFee: 0,
      otherCharges: 0,
      totalPrice: 0,
      quoteStatus: 'DRAFT — Pending Internal Approval'
    }
  }];
}

// Apply only numeric verified surcharges from rate table columns
let surchargeTotal = 0;
const fuelSurcharge = parseFloat(rateRow['Fuel Surcharge (USD/CBM)'] || '0');
const baf = parseFloat(rateRow['BAF (USD/CBM)'] || '0');
const otherSurcharge = parseFloat(rateRow['Other Surcharge (USD)'] || '0');

if (fuelSurcharge > 0) surchargeTotal += fuelSurcharge * cbm * usdThb;
if (baf > 0) surchargeTotal += baf * cbm * usdThb;
if (otherSurcharge > 0) surchargeTotal += otherSurcharge * usdThb;

const docFee = parseFloat($env.DOC_FEE || '500');
const minCharge = parseFloat(rateRow['Min Charge (THB)'] || 500);
const transitDays = shipmentType.includes('air')
  ? rateRow['Transit Air (days)']
  : rateRow['Transit Sea (days)'];

freightCharge = Math.max(freightCharge, minCharge);
const totalPrice = Math.ceil(freightCharge + surchargeTotal + docFee);

const validUntil = new Date();
validUntil.setDate(validUntil.getDate() + validityDays);

return [{
  json: {
    ...quoteData,
    requiresManualQuote: false,
    airRatePerKg: rateRow['Air Rate (THB/kg)'],
    transitDays,
    freightCharge: Math.ceil(freightCharge),
    docFee,
    otherCharges: Math.ceil(surchargeTotal),
    totalPrice,
    validUntil: validUntil.toISOString().slice(0, 10),
    surchargeNotes: rateRow['Surcharge Notes'] || '',
    quoteStatus: 'DRAFT — Pending Internal Approval'
  }
}];

// Filter rows that need follow-up today
const today = new Date().toISOString().slice(0, 10);
const rows = $input.all().map(r => r.json);

const dueFollowUps = rows.filter(row => {
  const followUpDate = (row['Follow-up Date'] || '').toString().slice(0, 10);
  const sentStatus = (row['Sent Status'] || '').toString();
  const bookingStatus = (row['Booking Status'] || '').toString();
  return followUpDate === today
    && sentStatus === 'Sent'
    && !['Booking Confirmed', 'Declined'].includes(bookingStatus);
});

return dueFollowUps.map(row => ({ json: row }));

